+
+        // [THEN] "Shortcut Dimension 1 Code" remains "V1".
+        // [THEN] "Dimension Set ID" is not changed.
+        ItemJournalLine.TestField("Shortcut Dimension 1 Code", DimensionValue[1].Code);
